void calculate_temp(int var_86,  //number of iteration
                     float *item_17,   //power input
                     float *elem_14,    //temperature input/output
                     float *data_19,    //temperature input/output
                     int val_61,  //Col of grid
                     int elem_93,  //Row of grid
                     int x_23,  // border offset 
                     int v_41,  // border offset
                     float elem_3,      //Capacitance
                     float tmp_71, 
                     float v_30, 
                     float tmp_43, 
