			for (k = 0; k < val_61; k++) {
				int index = j * val_61 + k;
				if (IN_RANGE(j, i + 1, elem_93 - i - 2) && IN_RANGE(k, i + 1, val_61 - i - 2)) {
					float var_8 = elem_14[index] + x_67 / elem_3 * (item_17[index] + (elem_14[(j + 1) * val_61 + k] + elem_14[(j - 1) * val_61 + k] - 2.0 * elem_14[index]) * (1 / v_30) + (elem_14[j * val_61 + k + 1] + elem_14[j * val_61 + k - 1] - 2.0 * elem_14[index]) * (1 / tmp_71) + (amb_temp - elem_14[index]) * (1 / tmp_43));
